#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, X;
        scanf("%d %d", &N, &X);
        int found = 0;
        for (int i = 0; i < N; ++i) {
            int a;
            scanf("%d", &a);
            if (a == X) found = 1;
        }
        if (found) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

